/**
 * Notification log model — tracks sent notification history.
 *
 * Each log entry captures the full context of a dispatched notification:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

/**
 * Delivery status of a logged notification.
 */
export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';

/**
 * A persisted record of a sent (or attempted) notification.
 */
export interface NotificationLog {
  /** Unique log entry ID */
  id: string;
  /** The notification ID from the notification system */
  notificationId: string;
  /** Recipient identifier (email, user ID, webhook URL, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Notification type */
  type: NotificationType;
  /** Delivery status */
  status: DeliveryStatus;
  /** When the notification was dispatched */
  timestamp: Date;
  /** Notification subject */
  subject: string;
  /** Notification priority */
  priority: NotificationPriority;
  /** Error message if delivery failed */
  error?: string;
  /** Optional metadata from the notification */
  metadata?: Record<string, unknown>;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationHistoryQuery {
  /** Filter by recipient */
  recipient?: string;
  /** Filter by notification type */
  type?: NotificationType;
  /** Filter by delivery channel */
  channel?: NotificationChannel;
  /** Filter by delivery status */
  status?: DeliveryStatus;
  /** Filter by date range start (inclusive) */
  from?: Date;
  /** Filter by date range end (inclusive) */
  to?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for searching history by recipient, type, channel, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
      subject: record['subject'] as string,
      priority: record['priority'] as string as NotificationLog['priority'],
      error: record['error'] as string | undefined,
      metadata: record['metadata']
        ? (JSON.parse(record['metadata'] as string) as Record<string, unknown>)
        : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
      subject: entity.subject,
      priority: entity.priority,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  /**
   * Find all log entries for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all log entries of a specific notification type.
   */
  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  /**
   * Find all log entries for a specific channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Find all log entries within a date range.
   */
  findByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.timestamp >= from && log.timestamp <= to,
    );
  }

  /**
   * Query log entries with multiple optional filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.from && log.timestamp < filters.from) return false;
      if (filters.to && log.timestamp > filters.to) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * This service provides:
 * - Logging of dispatched notifications (called by NotificationService)
 * - Querying notification history by recipient, type, channel, date range
 * - Retrieving individual log entries by ID or notification ID
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { Notification } from '../models/notification.js';
import type { NotificationLog, NotificationHistoryQuery, DeliveryStatus } from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a dispatched notification. Derives delivery status from the Notification object.
   */
  logNotification(notification: Notification): NotificationLog {
    const status = this.deriveStatus(notification);

    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.payload.id,
      recipient: notification.payload.recipient,
      channel: notification.payload.channel,
      type: notification.payload.type,
      status,
      timestamp: notification.payload.createdAt,
      subject: notification.payload.subject,
      priority: notification.payload.priority,
      error: this.extractError(notification),
      metadata: notification.payload.metadata,
    };

    this.repository.save(logEntry);
    this.logger.info(
      `Logged notification ${notification.payload.id} — ${status} via ${notification.payload.channel} to ${notification.payload.recipient}`,
    );

    return logEntry;
  }

  /**
   * Get a log entry by its ID.
   */
  getLogEntry(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get all log entries for a specific notification ID.
   */
  getByNotificationId(notificationId: string): NotificationLog[] {
    return this.repository.findAll((log) => log.notificationId === notificationId);
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries of a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.repository.findByDateRange(from, to);
  }

  /**
   * Query log entries with multiple optional filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.query(filters);
  }

  /**
   * Get total count of logged notifications.
   */
  getLogCount(): number {
    return this.repository.count();
  }

  /**
   * Derive delivery status from a Notification object.
   */
  private deriveStatus(notification: Notification): DeliveryStatus {
    if (notification.status === 'sent') return 'sent';
    // No results + failed = suppressed (e.g., by preferences) or no adapter
    if (notification.results.length === 0 && notification.status === 'failed') return 'suppressed';
    return 'failed';
  }

  /**
   * Extract error message from notification results.
   */
  private extractError(notification: Notification): string | undefined {
    const failedResult = notification.results.find((r) => !r.success);
    return failedResult?.error;
  }
}

