import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a successful notification', () => {
      const notification: Notification = {
        payload: {
          id: 'notif-0001',
          type: 'order-confirmation',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Order Confirmation: order-1',
          body: 'Your order has been placed.',
          priority: 'normal',
          createdAt: new Date('2026-01-15T10:00:00Z'),
          metadata: { userId: 'user-1' },
        },
        results: [
          {
            notificationId: 'notif-0001',
            channel: 'email',
            success: true,
            deliveredAt: new Date('2026-01-15T10:00:01Z'),
          },
        ],
        status: 'sent',
      };

      const log = historyService.logNotification(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order-confirmation');
      expect(log.status).toBe('sent');
      expect(log.subject).toBe('Order Confirmation: order-1');
      expect(log.priority).toBe('normal');
      expect(log.error).toBeUndefined();
      expect(log.metadata).toEqual({ userId: 'user-1' });
    });

    it('should log a failed notification with error', () => {
      const notification: Notification = {
        payload: {
          id: 'notif-0002',
          type: 'welcome',
          channel: 'email',
          recipient: 'bob@example.com',
          subject: 'Welcome',
          body: 'Welcome!',
          priority: 'normal',
          createdAt: new Date('2026-01-15T10:00:00Z'),
        },
        results: [
          {
            notificationId: 'notif-0002',
            channel: 'email',
            success: false,
            error: 'SMTP connection refused',
            deliveredAt: new Date('2026-01-15T10:00:01Z'),
          },
        ],
        status: 'failed',
      };

      const log = historyService.logNotification(notification);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('SMTP connection refused');
    });

    it('should log a suppressed notification (no results, failed status)', () => {
      const notification: Notification = {
        payload: {
          id: 'notif-0003',
          type: 'order-status-update',
          channel: 'email',
          recipient: 'user-1',
          subject: 'Order Update',
          body: 'Status changed.',
          priority: 'normal',
          createdAt: new Date('2026-01-15T10:00:00Z'),
          metadata: { userId: 'user-1' },
        },
        results: [],
        status: 'failed',
      };

      const log = historyService.logNotification(notification);

      expect(log.status).toBe('suppressed');
      expect(log.error).toBeUndefined();
    });

    it('should generate sequential log IDs', () => {
      const makeNotification = (id: string): Notification => ({
        payload: {
          id,
          type: 'welcome',
          channel: 'email',
          recipient: 'test@example.com',
          subject: 'Test',
          body: 'Test',
          priority: 'normal',
          createdAt: new Date(),
        },
        results: [{ notificationId: id, channel: 'email', success: true, deliveredAt: new Date() }],
        status: 'sent',
      });

      const log1 = historyService.logNotification(makeNotification('notif-0001'));
      const log2 = historyService.logNotification(makeNotification('notif-0002'));
      const log3 = historyService.logNotification(makeNotification('notif-0003'));

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
      expect(log3.id).toBe('nlog-0003');
    });
  });

  describe('query methods', () => {
    beforeEach(() => {
      // Seed log entries
      const entries: Notification[] = [
        {
          payload: {
            id: 'notif-0001',
            type: 'order-confirmation',
            channel: 'email',
            recipient: 'alice@example.com',
            subject: 'Order Confirmation',
            body: 'Your order',
            priority: 'normal',
            createdAt: new Date('2026-01-10T10:00:00Z'),
            metadata: { userId: 'user-1' },
          },
          results: [{ notificationId: 'notif-0001', channel: 'email', success: true, deliveredAt: new Date() }],
          status: 'sent',
        },
        {
          payload: {
            id: 'notif-0002',
            type: 'welcome',
            channel: 'email',
            recipient: 'bob@example.com',
            subject: 'Welcome',
            body: 'Welcome!',
            priority: 'normal',
            createdAt: new Date('2026-01-15T10:00:00Z'),
          },
          results: [{ notificationId: 'notif-0002', channel: 'email', success: true, deliveredAt: new Date() }],
          status: 'sent',
        },
        {
          payload: {
            id: 'notif-0003',
            type: 'order-status-update',
            channel: 'webhook',
            recipient: 'https://hooks.example.com/orders',
            subject: 'Order Update',
            body: 'Status changed',
            priority: 'high',
            createdAt: new Date('2026-01-20T10:00:00Z'),
          },
          results: [{ notificationId: 'notif-0003', channel: 'webhook', success: false, error: 'Timeout', deliveredAt: new Date() }],
          status: 'failed',
        },
        {
          payload: {
            id: 'notif-0004',
            type: 'order-confirmation',
            channel: 'email',
            recipient: 'alice@example.com',
            subject: 'Order Confirmation 2',
            body: 'Your second order',
            priority: 'normal',
            createdAt: new Date('2026-01-25T10:00:00Z'),
          },
          results: [{ notificationId: 'notif-0004', channel: 'email', success: true, deliveredAt: new Date() }],
          status: 'sent',
        },
      ];

      for (const n of entries) {
        historyService.logNotification(n);
      }
    });

    it('should get log entry by ID', () => {
      const entry = historyService.getLogEntry('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry!.notificationId).toBe('notif-0001');
    });

    it('should return undefined for nonexistent log ID', () => {
      expect(historyService.getLogEntry('nlog-9999')).toBeUndefined();
    });

    it('should get entries by notification ID', () => {
      const entries = historyService.getByNotificationId('notif-0002');
      expect(entries).toHaveLength(1);
      expect(entries[0]!.recipient).toBe('bob@example.com');
    });

    it('should get entries by recipient', () => {
      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(2);
      expect(entries.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should get entries by type', () => {
      const entries = historyService.getByType('order-confirmation');
      expect(entries).toHaveLength(2);
    });

    it('should get entries by date range', () => {
      const entries = historyService.getByDateRange(
        new Date('2026-01-12T00:00:00Z'),
        new Date('2026-01-22T00:00:00Z'),
      );
      expect(entries).toHaveLength(2);
      expect(entries.map((e) => e.notificationId).sort()).toEqual(['notif-0002', 'notif-0003']);
    });

    it('should query with multiple filters', () => {
      const entries = historyService.query({
        recipient: 'alice@example.com',
        type: 'order-confirmation',
      });
      expect(entries).toHaveLength(2);
    });

    it('should query by channel', () => {
      const entries = historyService.query({ channel: 'webhook' });
      expect(entries).toHaveLength(1);
      expect(entries[0]!.recipient).toBe('https://hooks.example.com/orders');
    });

    it('should query by status', () => {
      const entries = historyService.query({ status: 'failed' });
      expect(entries).toHaveLength(1);
      expect(entries[0]!.error).toBe('Timeout');
    });

    it('should return empty array when no matches', () => {
      const entries = historyService.query({ recipient: 'nobody@example.com' });
      expect(entries).toHaveLength(0);
    });

    it('should get log count', () => {
      expect(historyService.getLogCount()).toBe(4);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus, undefined, historyService);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      resetNotificationIdCounter();
    });

    it('should log notifications dispatched through NotificationService', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.notificationId).toBe('notif-0001');
    });

    it('should log failed notifications when no adapter is registered', async () => {
      const serviceNoAdapter = new NotificationService(eventBus, undefined, historyService);

      await serviceNoAdapter.dispatchNotification({
        type: 'welcome',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
      });

      const logs = historyService.getByRecipient('test@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('suppressed');
